// GENERATED brand artwork for the feature-showcase demo document.
// The mark is rendered from doc/logo.svg; the banner is a light-mode
// variant of doc/banner.svg. Both are base64-embedded so buildDemoPdf
// stays synchronous and asset-free. Regenerate with tool/gen_demo_brand_assets.sh.
import 'dart:convert';
import 'dart:typed_data';

/// 160×160 RGBA PNG of the dart-pdf app mark (doc/logo.svg).
Uint8List demoLogoPng() => base64Decode(_logo);

/// 960×300 RGB PNG of the light-mode dart-pdf banner.
Uint8List demoBannerPng() => base64Decode(_banner);

const String _logo = '';

const String _banner = '';
